#include <bits/stdc++.h>
#include <CGAL/Exact_predicates_inexact_constructions_kernel.h>
#include <CGAL/Delaunay_triangulation_2.h>
#include <CGAL/convex_hull_2.h>
using namespace std;
typedef CGAL::Exact_predicates_inexact_constructions_kernel K;
typedef K::Point_2 Point;
typedef CGAL::Delaunay_triangulation_2<K> Delaunay;
// point‑in‑convex‑polygon test (binary search) – works for strictly convex hull.
bool pointInConvex(const vector<Point>& hull, const Point& p){int n=hull.size(); if(n<3) return false; // degenerate
 // orientation of first triangle must be positive (counter‑clockwise)
 if(CGAL::orientation(hull[0], hull[1], hull[2])<0) {
 // make it CCW by reversing
 vector<Point> rev=hull; reverse(rev.begin(), rev.end()); return pointInConvex(rev,p);
 }
 // check if p is outside the fan [0,1] or [0,n-1]
 if(CGAL::orientation(hull[0], hull[1], p)<0) return false;
 if(CGAL::orientation(hull[0], hull[n-1], p)>0) return false;
 // binary search to find sector
 int lo=1, hi=n-1;
 while(hi-lo>1){int mid=(lo+hi)/2; if(CGAL::orientation(hull[0], hull[mid], p)>=0) lo=mid; else hi=mid;}
 // now p should be inside triangle hull[0], hull[lo], hull[lo+1]
 return CGAL::orientation(hull[lo], hull[lo+1], p)>=0;
}
int main(){ios::sync_with_stdio(false);cin.tie(nullptr);
 int T; if(!(cin>>T)) return 0; while(T--){int n;cin>>n; vector<Point> pts; pts.reserve(n);
 for(int i=0;i<n;i++){long long x,y;cin>>x>>y; pts.emplace_back(x,y);} if(n<3){cout<<"-1\n"; continue;}
 // convex hull
 vector<Point> hull; CGAL::convex_hull_2(pts.begin(), pts.end(), back_inserter(hull));
 // Delaunay triangulation
 Delaunay dt; dt.insert(pts.begin(), pts.end());
 double best=-1.0;
 for(auto fit=dt.finite_faces_begin(); fit!=dt.finite_faces_end(); ++fit){
   Point a=fit->vertex(0)->point();
   Point b=fit->vertex(1)->point();
   Point c=fit->vertex(2)->point();
   // circum‑centre
   K::Circle_2 circ = K::Circle_2(a,b,c);
   Point cc = circ.center();
   double r = sqrt(CGAL::squared_distance(cc,a));
   if(pointInConvex(hull, cc)){
       if(r>best) best=r;
   }
 }
 if(best<0) cout<<"-1\n"; else cout.setf(ios::fixed), cout<<setprecision(10)<<best<<"\n";
 }
 return 0; }

